import { useState, useEffect, useRef } from 'react';

const COLORS = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};

const font = "'JetBrains Mono', monospace";

const SPEEDS = [1, 2, 5, 10];

function BarReplayControlsInner({ totalBars = 200, onBarChange, onPlayPause }) {
  const [barIndex, setBarIndex] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [speed, setSpeed] = useState(1);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (playing) {
      const ms = Math.max(50, 500 / speed);
      intervalRef.current = setInterval(() => {
        setBarIndex(prev => {
          if (prev >= totalBars - 1) {
            setPlaying(false);
            onPlayPause && onPlayPause(false);
            return prev;
          }
          const next = prev + 1;
          onBarChange && onBarChange(next);
          return next;
        });
      }, ms);
    } else {
      clearInterval(intervalRef.current);
    }
    return () => clearInterval(intervalRef.current);
  }, [playing, speed, totalBars, onBarChange, onPlayPause]);

  const handlePlayPause = () => {
    const next = !playing;
    setPlaying(next);
    onPlayPause && onPlayPause(next);
  };

  const handleSlider = (e) => {
    const val = Number(e.target.value);
    setBarIndex(val);
    onBarChange && onBarChange(val);
    if (playing) {
      setPlaying(false);
      onPlayPause && onPlayPause(false);
    }
  };

  const step = (delta) => {
    setBarIndex(prev => {
      const next = Math.max(0, Math.min(totalBars - 1, prev + delta));
      onBarChange && onBarChange(next);
      return next;
    });
    if (playing) {
      setPlaying(false);
      onPlayPause && onPlayPause(false);
    }
  };

  const btnBase = {
    background: COLORS.surface,
    border: `1px solid ${COLORS.border}`,
    color: COLORS.text,
    borderRadius: 6,
    padding: '6px 12px',
    cursor: 'pointer',
    fontFamily: font,
    fontSize: 13,
    display: 'flex',
    alignItems: 'center',
    gap: 4,
    transition: 'background 0.15s',
  };

  const playBtnColor = playing ? COLORS.amber : COLORS.green;

  return (
    <div style={{
      background: COLORS.surface,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 10,
      padding: '10px 18px',
      display: 'flex',
      alignItems: 'center',
      gap: 16,
      flexWrap: 'wrap',
      fontFamily: font,
      userSelect: 'none',
    }}>
      {/* Bar counter */}
      <span style={{ color: COLORS.muted, fontSize: 13, minWidth: 90 }}>
        Bar{' '}
        <span style={{ color: COLORS.blue, fontWeight: 700 }}>{barIndex + 1}</span>
        <span style={{ color: COLORS.muted }}>/{totalBars}</span>
      </span>

      {/* Step back */}
      <button
        style={{ ...btnBase, padding: '6px 10px' }}
        onClick={() => step(-1)}
        title="Step Back"
        onMouseEnter={e => e.currentTarget.style.background = COLORS.border}
        onMouseLeave={e => e.currentTarget.style.background = COLORS.surface}
      >
        ◀
      </button>

      {/* Play / Pause */}
      <button
        style={{
          ...btnBase,
          background: playing ? '#1a1200' : '#0a1a10',
          border: `1px solid ${playBtnColor}`,
          color: playBtnColor,
          padding: '6px 16px',
          fontWeight: 700,
          minWidth: 80,
          justifyContent: 'center',
        }}
        onClick={handlePlayPause}
        onMouseEnter={e => e.currentTarget.style.opacity = '0.85'}
        onMouseLeave={e => e.currentTarget.style.opacity = '1'}
      >
        {playing ? '⏸ Pause' : '▶ Play'}
      </button>

      {/* Step forward */}
      <button
        style={{ ...btnBase, padding: '6px 10px' }}
        onClick={() => step(1)}
        title="Step Forward"
        onMouseEnter={e => e.currentTarget.style.background = COLORS.border}
        onMouseLeave={e => e.currentTarget.style.background = COLORS.surface}
      >
        ▶
      </button>

      {/* Slider */}
      <input
        type="range"
        min={0}
        max={totalBars - 1}
        value={barIndex}
        onChange={handleSlider}
        style={{
          flex: 1,
          minWidth: 120,
          accentColor: COLORS.blue,
          cursor: 'pointer',
          height: 4,
        }}
      />

      {/* Speed selector */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
        <span style={{ color: COLORS.muted, fontSize: 11 }}>Speed</span>
        <div style={{ display: 'flex', gap: 4 }}>
          {SPEEDS.map(s => (
            <button
              key={s}
              onClick={() => setSpeed(s)}
              style={{
                ...btnBase,
                padding: '4px 9px',
                fontSize: 11,
                background: speed === s ? COLORS.blue + '22' : COLORS.surface,
                border: `1px solid ${speed === s ? COLORS.blue : COLORS.border}`,
                color: speed === s ? COLORS.blue : COLORS.muted,
              }}
              onMouseEnter={e => { if (speed !== s) e.currentTarget.style.borderColor = COLORS.muted; }}
              onMouseLeave={e => { if (speed !== s) e.currentTarget.style.borderColor = COLORS.border; }}
            >
              {s}x
            </button>
          ))}
        </div>
      </div>

      {/* Reset */}
      <button
        style={{ ...btnBase, padding: '4px 10px', fontSize: 11, color: COLORS.muted }}
        onClick={() => { setBarIndex(0); setPlaying(false); onBarChange && onBarChange(0); onPlayPause && onPlayPause(false); }}
        onMouseEnter={e => e.currentTarget.style.background = COLORS.border}
        onMouseLeave={e => e.currentTarget.style.background = COLORS.surface}
        title="Reset to start"
      >
        ↺
      </button>
    </div>
  );
}

// Generate demo OHLC bars for the standalone page view
function generateDemoBars(count) {
  const bars = [];
  let price = 450;
  for (let i = 0; i < count; i++) {
    const open = price;
    const change = (Math.random() - 0.48) * 8;
    const close = open + change;
    const high = Math.max(open, close) + Math.random() * 4;
    const low = Math.min(open, close) - Math.random() * 4;
    bars.push({ open: +open.toFixed(2), high: +high.toFixed(2), low: +low.toFixed(2), close: +close.toFixed(2) });
    price = close;
  }
  return bars;
}

// Standalone page wrapper — renders the control bar with a mini chart
export default function BarReplayControls(props) {
  // If used as an embedded component with callbacks, render just the controls
  if (props.onBarChange || props.onPlayPause) {
    return <BarReplayControlsInner {...props} />;
  }

  // Standalone page mode
  const [demoBars] = useState(() => generateDemoBars(200));
  const [visibleBars, setVisibleBars] = useState(50);

  const handleBarChange = (idx) => {
    setVisibleBars(Math.max(2, idx + 1));
  };

  const barsToShow = demoBars.slice(0, visibleBars);
  const chartH = 300;
  const chartW = 800;
  const barW = Math.max(2, (chartW - 60) / barsToShow.length);
  const allPrices = barsToShow.flatMap(b => [b.high, b.low]);
  const minP = Math.min(...allPrices);
  const maxP = Math.max(...allPrices);
  const rangeP = maxP - minP || 1;

  return (
    <div style={{ background: COLORS.bg, minHeight: '100vh', padding: 24, fontFamily: font, color: COLORS.text }}>
      <div style={{ maxWidth: 900, margin: '0 auto' }}>
        <h1 style={{ fontSize: 22, fontWeight: 700, margin: '0 0 4px' }}>Bar Replay</h1>
        <p style={{ color: COLORS.muted, fontSize: 13, margin: '0 0 20px' }}>
          Step through historical price action bar-by-bar. Practice pattern recognition and entries.
        </p>

        {/* Mini candlestick chart */}
        <div style={{
          background: COLORS.surface, border: `1px solid ${COLORS.border}`,
          borderRadius: 10, padding: 16, marginBottom: 16, overflowX: 'auto',
        }}>
          <svg width={chartW} height={chartH} style={{ display: 'block' }}>
            {barsToShow.map((bar, i) => {
              const x = 40 + i * barW + barW / 2;
              const yHigh = 10 + (1 - (bar.high - minP) / rangeP) * (chartH - 30);
              const yLow = 10 + (1 - (bar.low - minP) / rangeP) * (chartH - 30);
              const yOpen = 10 + (1 - (bar.open - minP) / rangeP) * (chartH - 30);
              const yClose = 10 + (1 - (bar.close - minP) / rangeP) * (chartH - 30);
              const bullish = bar.close >= bar.open;
              const color = bullish ? COLORS.green : COLORS.red;
              const bodyTop = Math.min(yOpen, yClose);
              const bodyH = Math.max(1, Math.abs(yOpen - yClose));
              return (
                <g key={i}>
                  <line x1={x} y1={yHigh} x2={x} y2={yLow} stroke={color} strokeWidth={1} />
                  <rect x={x - barW * 0.3} y={bodyTop} width={barW * 0.6} height={bodyH} fill={color} rx={0.5} />
                </g>
              );
            })}
            {/* Price axis labels */}
            {[0, 0.25, 0.5, 0.75, 1].map(pct => {
              const y = 10 + pct * (chartH - 30);
              const val = maxP - pct * rangeP;
              return (
                <text key={pct} x={2} y={y + 3} fill={COLORS.muted} fontSize={9} fontFamily={font}>
                  {val.toFixed(0)}
                </text>
              );
            })}
          </svg>
        </div>

        {/* Controls */}
        <BarReplayControlsInner
          totalBars={demoBars.length}
          onBarChange={handleBarChange}
          onPlayPause={() => {}}
        />

        <div style={{
          marginTop: 16, padding: '10px 14px', background: COLORS.surface,
          border: `1px solid ${COLORS.border}`, borderRadius: 10,
          fontSize: 11, color: COLORS.muted, fontFamily: font,
        }}>
          Showing {visibleBars} of {demoBars.length} bars. Use the controls above to step through price action.
        </div>
      </div>
    </div>
  );
}
